"use client"

import { useState, useMemo } from "react"
import { ColumnDef } from "@tanstack/react-table"
import { AdminDashboardLayout } from "@/components/admin/admin-dashboard-layout"
import { AdminTable, AdminTableSortHeader } from "@/components/admin/admin-table"
import { AdminButton } from "@/components/admin/admin-button"
import { AdminInput } from "@/components/admin/admin-input"
import { AdminModal, AdminModalHeader, AdminModalBody, AdminModalFooter } from "@/components/admin/admin-modal"
import { AdminTabs } from "@/components/admin/admin-tabs"
import { Checkbox } from "@/components/ui/checkbox"
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group"
import { Label } from "@/components/ui/label"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import {
  Users, Briefcase, Building2, User, Mail, MapPin,
  CheckCircle2, Clock, XCircle, Plus, Search, ToggleLeft,
  ToggleRight, Download, ShieldOff, Pencil, Gift, Calendar, Percent, X,
} from "lucide-react"

// ─── Types ────────────────────────────────────────────────────────────────────
type ClienteStatus    = "ativo" | "pendente" | "inativo"
type StatusFinanceiro = "em_dia" | "vencido" | "bloqueado"
type CondicaoTipo     = "padrao" | "especial"

interface Cliente {
  id: string
  nome: string
  tipo: "pj" | "pf" | "franqueado"
  plano: "basico" | "profissional" | "empresarial"
  documento: string
  email: string
  telefone: string
  cidade: string
  status: ClienteStatus
  statusFinanceiro: StatusFinanceiro
  desde: string
}

interface Condicao {
  id: string
  clienteId: string
  clienteNome: string
  clienteTipo: "pf" | "pj" | "franqueado"
  tipoCondicao: "funcoes_pj" | "desconto" | "prazo_especial"
  desconto: number
  prazo: number
  vigenciaInicio: string
  vigenciaFim: string
  status: "ativo" | "expirado"
}

const planoConfig: Record<Cliente["plano"], { label: string; className: string }> = {
  basico: { label: "Básico", className: "bg-gray-100 text-gray-700" },
  profissional: { label: "Profissional", className: "bg-blue-50 text-blue-700" },
  empresarial: { label: "Empresarial", className: "bg-purple-50 text-purple-700" },
}

// ─── Mock data ────────────────────────────────────────────────────────────────
const CLIENTES: Cliente[] = [
  { id: "1", nome: "Construtora Alfa Ltda",    tipo: "pj", plano: "empresarial",  documento: "12.345.678/0001-90", email: "contato@alfa.com.br",     telefone: "(11) 99999-0001", cidade: "São Paulo, SP",       status: "ativo",    statusFinanceiro: "em_dia",  desde: "Jan 2023" },
  { id: "2", nome: "Imobiliária Beta S.A.",     tipo: "pj", plano: "profissional", documento: "98.765.432/0001-10", email: "admin@beta.com.br",       telefone: "(21) 98888-0002", cidade: "Rio de Janeiro, RJ",  status: "ativo",    statusFinanceiro: "vencido", desde: "Mar 2023" },
  { id: "3", nome: "Carlos Eduardo Mendes",    tipo: "pf", plano: "basico",       documento: "321.654.987-00",     email: "carlos.m@gmail.com",      telefone: "(31) 97777-0003", cidade: "Belo Horizonte, MG",  status: "pendente", statusFinanceiro: "em_dia",  desde: "Nov 2023" },
  { id: "4", nome: "Administradora Gama Ltda", tipo: "pj", plano: "empresarial",  documento: "55.444.333/0001-22", email: "gama@administradora.com", telefone: "(41) 96666-0004", cidade: "Curitiba, PR",        status: "inativo",  statusFinanceiro: "bloqueado",desde: "Jul 2022" },
  { id: "5", nome: "Ana Paula Ferreira",       tipo: "pf", plano: "profissional", documento: "111.222.333-44",     email: "ana.ferreira@email.com",  telefone: "(51) 95555-0005", cidade: "Porto Alegre, RS",    status: "ativo",    statusFinanceiro: "em_dia",  desde: "Fev 2024" },
  { id: "6", nome: "Roberto Lima ME",          tipo: "pj", plano: "basico",       documento: "77.888.999/0001-55", email: "roberto@limame.com.br",   telefone: "(11) 94444-0006", cidade: "Campinas, SP",        status: "ativo",    statusFinanceiro: "vencido", desde: "Ago 2023" },
  { id: "7", nome: "Mariana Costa",            tipo: "pf", plano: "basico",       documento: "999.888.777-66",     email: "mari.costa@email.com",    telefone: "(11) 93333-0007", cidade: "São Paulo, SP",       status: "ativo",    statusFinanceiro: "em_dia",  desde: "Mai 2024" },
  { id: "8", nome: "Delta Engenharia Ltda",    tipo: "pj", plano: "profissional", documento: "22.333.444/0001-88", email: "contato@deltaeng.com",    telefone: "(41) 92222-0008", cidade: "Curitiba, PR",        status: "inativo",  statusFinanceiro: "bloqueado",desde: "Jan 2022" },
]

const CONDICOES: Condicao[] = [
  { id: "1", clienteId: "1", clienteNome: "Construtora Alfa Ltda", clienteTipo: "pj", tipoCondicao: "desconto", desconto: 15, prazo: 30, vigenciaInicio: "01/01/2025", vigenciaFim: "31/12/2025", status: "ativo" },
  { id: "2", clienteId: "2", clienteNome: "Imobiliária Beta S.A.", clienteTipo: "pj", tipoCondicao: "prazo_especial", desconto: 10, prazo: 45, vigenciaInicio: "01/01/2025", vigenciaFim: "30/06/2025", status: "ativo" },
  { id: "3", clienteId: "3", clienteNome: "Carlos Eduardo Mendes", clienteTipo: "pf", tipoCondicao: "funcoes_pj", desconto: 5, prazo: 15, vigenciaInicio: "01/11/2024", vigenciaFim: "28/02/2025", status: "ativo" },
  { id: "4", clienteId: "5", clienteNome: "Ana Paula Ferreira", clienteTipo: "pf", tipoCondicao: "funcoes_pj", desconto: 0, prazo: 7, vigenciaInicio: "01/12/2024", vigenciaFim: "01/06/2025", status: "ativo" },
]

// ─── Helpers ──────────────────────────────────────────────────────────────────
const statusConfig: Record<ClienteStatus, { label: string; className: string; icon: React.ElementType }> = {
  ativo:    { label: "Ativo",    className: "bg-green-50 text-green-700",   icon: CheckCircle2 },
  pendente: { label: "Pendente", className: "bg-yellow-50 text-yellow-700", icon: Clock },
  inativo:  { label: "Inativo",  className: "bg-gray-100 text-gray-500",    icon: XCircle },
}

const financeiroConfig: Record<StatusFinanceiro, { label: string; className: string }> = {
  em_dia:   { label: "Em dia",   className: "bg-green-50 text-green-700"  },
  vencido:  { label: "Vencido",  className: "bg-orange-50 text-orange-600" },
  bloqueado:{ label: "Bloqueado",className: "bg-red-50 text-red-600"      },
}

const tipoCondicaoConfig: Record<Condicao["tipoCondicao"], { label: string; className: string }> = {
  funcoes_pj: { label: "Funções PJ", className: "bg-purple-50 text-purple-700" },
  desconto: { label: "Desconto", className: "bg-emerald-50 text-emerald-700" },
  prazo_especial: { label: "Prazo Especial", className: "bg-blue-50 text-blue-700" },
}

// ─── Colunas Condições ────────────────────────────────────────────────────────
const colunasCondicoes: ColumnDef<Condicao>[] = [
  {
    accessorKey: "clienteNome",
    header: ({ column }) => <AdminTableSortHeader column={column} label="Cliente" />,
    cell: ({ row }) => (
      <div className="flex items-center gap-3">
        <div className="h-9 w-9 rounded-full bg-[#0B7A8F]/10 flex items-center justify-center shrink-0">
          {row.original.clienteTipo === "pj" ? <Building2 size={15} className="text-[#0B7A8F]" /> : <User size={15} className="text-[#0B7A8F]" />}
        </div>
        <div>
          <p className="text-sm font-medium text-gray-800">{row.original.clienteNome}</p>
          <span className="text-xs text-gray-400 uppercase">{row.original.clienteTipo === "pf" ? "Pessoa Física" : "Pessoa Jurídica"}</span>
        </div>
      </div>
    ),
  },
  {
    accessorKey: "tipoCondicao",
    header: "Condição",
    cell: ({ row }) => {
      const cfg = tipoCondicaoConfig[row.original.tipoCondicao]
      return (
        <span className={`text-xs font-medium px-2.5 py-1 rounded-full ${cfg.className}`}>
          {cfg.label}
        </span>
      )
    },
  },
  {
    accessorKey: "desconto",
    header: "Desconto",
    cell: ({ row }) => (
      <span className="text-sm font-semibold text-gray-800">
        {row.original.desconto > 0 ? `${row.original.desconto}%` : "—"}
      </span>
    ),
  },
  {
    accessorKey: "prazo",
    header: "Prazo pgto.",
    cell: ({ row }) => <span className="text-sm text-gray-600">{row.original.prazo} dias</span>,
  },
  {
    accessorKey: "vigenciaFim",
    header: "Vigência",
    cell: ({ row }) => (
      <div className="text-xs text-gray-500">
        <span>{row.original.vigenciaInicio}</span>
        <span className="mx-1">→</span>
        <span className="font-medium text-gray-700">{row.original.vigenciaFim}</span>
      </div>
    ),
  },
  {
    accessorKey: "status",
    header: "Status",
    cell: ({ row }) => (
      <span className={`text-xs font-medium px-2.5 py-1 rounded-full ${
        row.original.status === "ativo" ? "bg-green-50 text-green-700" : "bg-gray-100 text-gray-500"
      }`}>
        {row.original.status === "ativo" ? "Ativo" : "Expirado"}
      </span>
    ),
  },
]

// ─── Page ─────────────────────────────────────────────────────────────────────
type Aba = "clientes" | "condicoes"

export default function BackofficeClientesPage() {
  const [aba, setAba] = useState<Aba>("clientes")

  // Filtros
  const [busca, setBusca] = useState("")
  const [filtroTipo, setFiltroTipo] = useState("all")
  const [filtroFinanceiro, setFiltroFinanceiro] = useState("all")

  // Seleção em lote
  const [selecionados, setSelecionados] = useState<Set<string>>(new Set())

  // Modal novo cliente
  const [showModalNovoCliente, setShowModalNovoCliente] = useState(false)
  const [novoCliente, setNovoCliente] = useState({
    tipo: "pf", nome: "", documento: "", email: "",
    estado: "", unidade: "", cobranca: "avulso", enviarEmail: true,
  })

  // Modal editar cliente
  const [clienteEditando, setClienteEditando] = useState<Cliente | null>(null)
  const [dadosEdicao, setDadosEdicao] = useState({
    nome: "", documento: "", email: "", telefone: "", cidade: "",
    tipo: "pf", status: "ativo" as ClienteStatus,
  })

  const abrirEdicao = (c: Cliente) => {
    setDadosEdicao({
      nome: c.nome, documento: c.documento, email: c.email,
      telefone: c.telefone, cidade: c.cidade,
      tipo: c.tipo, status: c.status,
    })
    setClienteEditando(c)
  }

  const handleSalvarEdicao = () => {
    setClienteEditando(null)
  }

  // ─── Estado Condições Comerciais ────────────────────────────────────────────
  const [buscaCondicao, setBuscaCondicao] = useState("")
  const [clienteSelecionado, setClienteSelecionado] = useState<Cliente | null>(null)
  const [showModalCondicao, setShowModalCondicao] = useState(false)
  const [novaCondicao, setNovaCondicao] = useState({
    tipoCondicao: "funcoes_pj" as Condicao["tipoCondicao"],
    desconto: 0,
    prazo: 7,
    vigenciaInicio: "",
    vigenciaFim: "",
  })

  const clientesBuscados = useMemo(() => {
    if (!buscaCondicao.trim()) return []
    const termo = buscaCondicao.toLowerCase()
    return CLIENTES.filter((c) =>
      [c.nome, c.documento, c.email].some((v) => v.toLowerCase().includes(termo))
    ).slice(0, 5)
  }, [buscaCondicao])

  const handleSelecionarCliente = (cliente: Cliente) => {
    setClienteSelecionado(cliente)
    setBuscaCondicao("")
    // Se for PF, sugere "Funções PJ", se for PJ, sugere "Desconto"
    setNovaCondicao({
      tipoCondicao: cliente.tipo === "pf" ? "funcoes_pj" : "desconto",
      desconto: cliente.tipo === "pj" ? 10 : 0,
      prazo: 7,
      vigenciaInicio: new Date().toLocaleDateString("pt-BR"),
      vigenciaFim: "",
    })
    setShowModalCondicao(true)
  }

  const handleSalvarCondicao = () => {
    // Aqui salvaria no banco
    setShowModalCondicao(false)
    setClienteSelecionado(null)
    setNovaCondicao({
      tipoCondicao: "funcoes_pj",
      desconto: 0,
      prazo: 7,
      vigenciaInicio: "",
      vigenciaFim: "",
    })
  }

  const handleCancelarCondicao = () => {
    setShowModalCondicao(false)
    setClienteSelecionado(null)
  }

  const isCondicaoFormValid = novaCondicao.vigenciaFim !== ""

  // Filtros condições
  const [buscaListaCondicoes, setBuscaListaCondicoes] = useState("")
  const [filtroCondicaoTipo, setFiltroCondicaoTipo] = useState("all")
  const [filtroCondicaoDesconto, setFiltroCondicaoDesconto] = useState("all")
  const [filtroCondicaoPrazo, setFiltroCondicaoPrazo] = useState("all")
  const [filtroCondicaoVigencia, setFiltroCondicaoVigencia] = useState("all")
  const [filtroCondicaoStatus, setFiltroCondicaoStatus] = useState("all")

  const condicoesFiltradas = useMemo(() => {
    return CONDICOES.filter((c) => {
      const matchBusca = !buscaListaCondicoes || c.clienteNome.toLowerCase().includes(buscaListaCondicoes.toLowerCase())
      const matchTipo = filtroCondicaoTipo === "all" || c.tipoCondicao === filtroCondicaoTipo
      const matchDesconto = filtroCondicaoDesconto === "all"
        || (filtroCondicaoDesconto === "com" && c.desconto > 0)
        || (filtroCondicaoDesconto === "sem" && c.desconto === 0)
      const matchPrazo = filtroCondicaoPrazo === "all"
        || (filtroCondicaoPrazo === "curto" && c.prazo <= 15)
        || (filtroCondicaoPrazo === "medio" && c.prazo > 15 && c.prazo <= 30)
        || (filtroCondicaoPrazo === "longo" && c.prazo > 30)
      const hoje = new Date()
      const [d, m, y] = c.vigenciaFim.split("/").map(Number)
      const fimDate = new Date(y, m - 1, d)
      const matchVigencia = filtroCondicaoVigencia === "all"
        || (filtroCondicaoVigencia === "vence30" && fimDate > hoje && (fimDate.getTime() - hoje.getTime()) / 86400000 <= 30)
        || (filtroCondicaoVigencia === "vigente" && fimDate >= hoje)
        || (filtroCondicaoVigencia === "expirado" && fimDate < hoje)
      const matchStatus = filtroCondicaoStatus === "all" || c.status === filtroCondicaoStatus
      return matchBusca && matchTipo && matchDesconto && matchPrazo && matchVigencia && matchStatus
    })
  }, [buscaListaCondicoes, filtroCondicaoTipo, filtroCondicaoDesconto, filtroCondicaoPrazo, filtroCondicaoVigencia, filtroCondicaoStatus])

  const isFormValid = novoCliente.nome && novoCliente.documento && novoCliente.email && novoCliente.estado && novoCliente.unidade

  const handleCriarCliente = () => {
    setShowModalNovoCliente(false)
    setNovoCliente({ tipo: "pf", nome: "", documento: "", email: "", estado: "", unidade: "", cobranca: "avulso", enviarEmail: true })
  }

  // Dados filtrados
  const clientesFiltrados = useMemo(() => {
    const termo = busca.toLowerCase()
    return CLIENTES.filter((c) => {
      const matchBusca = !termo || [c.nome, c.documento, c.email, c.cidade].some((v) => v.toLowerCase().includes(termo))
      const matchTipo = filtroTipo === "all" || c.tipo === filtroTipo
      const matchFin  = filtroFinanceiro === "all" || c.statusFinanceiro === filtroFinanceiro
      return matchBusca && matchTipo && matchFin
    })
  }, [busca, filtroTipo, filtroFinanceiro])

  const todosSelected = clientesFiltrados.length > 0 && clientesFiltrados.every((c) => selecionados.has(c.id))

  const toggleAll = () => {
    if (todosSelected) {
      setSelecionados((prev) => {
        const next = new Set(prev)
        clientesFiltrados.forEach((c) => next.delete(c.id))
        return next
      })
    } else {
      setSelecionados((prev) => {
        const next = new Set(prev)
        clientesFiltrados.forEach((c) => next.add(c.id))
        return next
      })
    }
  }

  const toggleOne = (id: string) => {
    setSelecionados((prev) => {
      const next = new Set(prev)
      next.has(id) ? next.delete(id) : next.add(id)
      return next
    })
  }

  // Colunas com checkbox
  const colunasClientes: ColumnDef<Cliente>[] = [
    {
      id: "select",
      header: () => (
        <Checkbox
          checked={todosSelected}
          onCheckedChange={toggleAll}
          className="cursor-pointer"
        />
      ),
      cell: ({ row }) => (
        <Checkbox
          checked={selecionados.has(row.original.id)}
          onCheckedChange={() => toggleOne(row.original.id)}
          className="cursor-pointer"
        />
      ),
      size: 40,
    },
    {
      accessorKey: "nome",
      header: ({ column }) => <AdminTableSortHeader column={column} label="Cliente" />,
      cell: ({ row }) => {
        const c = row.original
        return (
          <div className="flex items-center gap-3">
            <div className="h-9 w-9 rounded-full bg-[#0B7A8F]/10 flex items-center justify-center shrink-0">
              {c.tipo === "pj" || c.tipo === "franqueado"
                ? <Building2 size={15} className="text-[#0B7A8F]" />
                : <User size={15} className="text-[#0B7A8F]" />}
            </div>
            <div className="min-w-0">
              <div className="flex items-center gap-2">
                <p className="text-sm font-semibold text-gray-800 truncate">{c.nome}</p>
                <span className="text-xs font-medium px-1.5 py-0.5 rounded bg-gray-100 text-gray-500 uppercase tracking-wide">
                  {c.tipo === "pf" ? "PF" : c.tipo === "pj" ? "PJ" : "Franq."}
                </span>
              </div>
              <div className="flex flex-wrap items-center gap-x-3 gap-y-0.5 mt-0.5">
                <span className="text-xs text-gray-400">{c.documento}</span>
                <span className="flex items-center gap-1 text-xs text-gray-400"><Mail size={11} />{c.email}</span>
                <span className="flex items-center gap-1 text-xs text-gray-400"><MapPin size={11} />{c.cidade}</span>
              </div>
            </div>
          </div>
        )
      },
    },
    {
      accessorKey: "statusFinanceiro",
      header: ({ column }) => <AdminTableSortHeader column={column} label="Financeiro" />,
      cell: ({ row }) => {
        const f = financeiroConfig[row.original.statusFinanceiro]
        return (
          <span className={`inline-flex items-center text-xs font-medium px-2.5 py-1 rounded-full ${f.className}`}>
            {f.label}
          </span>
        )
      },
    },
    {
      accessorKey: "status",
      header: ({ column }) => <AdminTableSortHeader column={column} label="Status" />,
      cell: ({ row }) => {
        const s = statusConfig[row.original.status]
        const Icon = s.icon
        return (
          <span className={`inline-flex items-center gap-1.5 text-xs font-medium px-2.5 py-1 rounded-full ${s.className}`}>
            <Icon size={11} />{s.label}
          </span>
        )
      },
    },
    {
      accessorKey: "desde",
      header: ({ column }) => <AdminTableSortHeader column={column} label="Desde" />,
      cell: ({ row }) => <span className="text-xs text-gray-400">{row.original.desde}</span>,
    },
    {
      id: "acoes",
      header: "",
      cell: ({ row }) => (
        <div className="flex justify-end">
          <button
            onClick={() => abrirEdicao(row.original)}
            className="p-1.5 text-gray-500 hover:text-[#0B7A8F] transition-colors rounded hover:bg-gray-100"
            title="Editar cliente"
          >
            <Pencil size={16} />
          </button>
        </div>
      ),
      size: 80,
    },
  ]

  const abas: { id: Aba; label: string; icon: React.ElementType }[] = [
    { id: "clientes",  label: "Clientes",             icon: Users },
    { id: "condicoes", label: "Condições comerciais", icon: Briefcase },
  ]

  return (
    <AdminDashboardLayout profile="backoffice" title="Clientes">
      <div className="space-y-4">

        {/* Abas */}
        <AdminTabs value={aba} onChange={setAba} tabs={abas} />

        {aba === "clientes" && (
          <>
            {/* Filtros + Novo Cliente */}
            <div className="flex flex-wrap items-end gap-3">

              {/* Busca */}
              <div className="flex flex-col gap-1 flex-1 min-w-[200px]">
                <label className="text-xs font-medium text-gray-500">Buscar</label>
                <AdminInput
