                    max={100}
                    value={novaCondicao.desconto}
                    onChange={(e) => setNovaCondicao((p) => ({ ...p, desconto: Number(e.target.value) }))}
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-medium text-gray-700">Prazo de pagamento (dias)</label>
                  <AdminInput
                    variant="form"
                    type="number"
                    min={1}
                    value={novaCondicao.prazo}
                    onChange={(e) => setNovaCondicao((p) => ({ ...p, prazo: Number(e.target.value) }))}
                  />
                </div>
              </div>
            )}

            {novaCondicao.tipoCondicao === "prazo_especial" && (
              <div className="space-y-2">
                <label className="text-sm font-medium text-gray-700">Prazo de pagamento (dias)</label>
                <AdminInput
                  variant="form"
                  type="number"
                  min={1}
                  value={novaCondicao.prazo}
                  onChange={(e) => setNovaCondicao((p) => ({ ...p, prazo: Number(e.target.value) }))}
                />
              </div>
            )}

            {/* Vigência */}
            <div className="space-y-2">
              <label className="text-sm font-medium text-gray-700 flex items-center gap-2">
                <Calendar size={14} />
                Vigência da Condição
              </label>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <span className="text-xs text-gray-500">Data início</span>
                  <AdminInput
                    variant="form"
                    type="date"
                    value={novaCondicao.vigenciaInicio}
                    onChange={(e) => setNovaCondicao((p) => ({ ...p, vigenciaInicio: e.target.value }))}
                  />
                </div>
                <div className="space-y-1">
                  <span className="text-xs text-gray-500">Data fim</span>
                  <AdminInput
                    variant="form"
                    type="date"
                    value={novaCondicao.vigenciaFim}
                    onChange={(e) => setNovaCondicao((p) => ({ ...p, vigenciaFim: e.target.value }))}
                  />
                </div>
              </div>
            </div>

            {/* Resumo */}
            <div className="p-4 bg-[#0B7A8F]/5 border border-[#0B7A8F]/20 rounded-xl">
              <p className="text-sm font-medium text-[#0B7A8F]">Resumo da Condição</p>
              <ul className="mt-2 space-y-1 text-sm text-gray-600">
                <li>• Tipo: <span className="font-medium">{tipoCondicaoConfig[novaCondicao.tipoCondicao].label}</span></li>
                {novaCondicao.desconto > 0 && <li>• Desconto: <span className="font-medium">{novaCondicao.desconto}%</span></li>}
                <li>• Prazo: <span className="font-medium">{novaCondicao.prazo} dias</span></li>
                {novaCondicao.vigenciaFim && <li>• Válido até: <span className="font-medium">{novaCondicao.vigenciaFim}</span></li>}
              </ul>
            </div>
          </AdminModalBody>
          <AdminModalFooter>
            <AdminButton variant="outline" onClick={handleCancelarCondicao}>Cancelar</AdminButton>
            <AdminButton variant="primary" onClick={handleSalvarCondicao} disabled={!isCondicaoFormValid}>
              Salvar Condição
            </AdminButton>
          </AdminModalFooter>
        </AdminModal>
      )}
    </AdminDashboardLayout>
  )
}

