                <AdminInput variant="form" placeholder={novoCliente.tipo === "pf" ? "000.000.000-00" : "00.000.000/0000-00"} value={novoCliente.documento} onChange={(e) => setNovoCliente((p) => ({ ...p, documento: e.target.value }))} />
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium text-gray-700">E-mail principal</label>
              <AdminInput variant="form" placeholder="email@empresa.com.br" value={novoCliente.email} onChange={(e) => setNovoCliente((p) => ({ ...p, email: e.target.value }))} icon={<Mail size={15} />} />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="text-sm font-medium text-gray-700">Estado</label>
                <Select value={novoCliente.estado} onValueChange={(v) => setNovoCliente((p) => ({ ...p, estado: v }))}>
                  <SelectTrigger><SelectValue placeholder="Selecione o estado" /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="SP">São Paulo</SelectItem>
                    <SelectItem value="RJ">Rio de Janeiro</SelectItem>
                    <SelectItem value="MG">Minas Gerais</SelectItem>
                    <SelectItem value="PR">Paraná</SelectItem>
                    <SelectItem value="RS">Rio Grande do Sul</SelectItem>
                    <SelectItem value="SC">Santa Catarina</SelectItem>
                    <SelectItem value="BA">Bahia</SelectItem>
                    <SelectItem value="DF">Distrito Federal</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-gray-700">Unidade</label>
                <Select value={novoCliente.unidade} onValueChange={(v) => setNovoCliente((p) => ({ ...p, unidade: v }))}>
                  <SelectTrigger><SelectValue placeholder="Selecione a unidade" /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="matriz">Matriz</SelectItem>
                    <SelectItem value="filial-sp">Filial SP</SelectItem>
                    <SelectItem value="filial-rj">Filial RJ</SelectItem>
                    <SelectItem value="filial-mg">Filial MG</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium text-gray-700">Tipo de cobrança inicial</label>
              <RadioGroup value={novoCliente.cobranca} onValueChange={(v) => setNovoCliente((p) => ({ ...p, cobranca: v }))} className="flex gap-4">
                <div className="flex items-center gap-2">
                  <RadioGroupItem value="avulso" id="cobranca-avulso" />
                  <div>
                    <Label htmlFor="cobranca-avulso">Avulso</Label>
                    <p className="text-xs text-gray-400">Pagamento por vistoria</p>
                  </div>
                </div>
                <div className="flex items-center gap-2">
                  <RadioGroupItem value="faturado" id="cobranca-faturado" />
                  <div>
                    <Label htmlFor="cobranca-faturado">Faturado</Label>
                    <p className="text-xs text-gray-400">Faturamento mensal</p>
                  </div>
                </div>
              </RadioGroup>
            </div>
            <div className="flex items-center gap-3 p-4 bg-blue-50 rounded-xl border border-blue-100">
              <Checkbox id="enviarEmail" checked={novoCliente.enviarEmail} onCheckedChange={(v) => setNovoCliente((p) => ({ ...p, enviarEmail: !!v }))} />
              <Label htmlFor="enviarEmail" className="text-sm text-blue-800 cursor-pointer">
                Enviar acesso ao sistema via e-mail para o cliente
              </Label>
            </div>
          </AdminModalBody>
          <AdminModalFooter>
            <AdminButton variant="outline" onClick={() => setShowModalNovoCliente(false)}>Cancelar</AdminButton>
            <AdminButton variant="primary" onClick={handleCriarCliente} disabled={!isFormValid}>Cadastrar Cliente</AdminButton>
          </AdminModalFooter>
        </AdminModal>
      )}

      {/* ── Modal Editar Cliente ─────────────────────────────────────────────── */}
      {clienteEditando && (
        <AdminModal onClose={() => setClienteEditando(null)} size="md">
          <AdminModalHeader
            title="Editar Cliente"
            subtitle={`Atualize os dados de ${clienteEditando.nome}`}
            onClose={() => setClienteEditando(null)}
          />
          <AdminModalBody>
            <div className="space-y-2">
              <label className="text-sm font-medium text-gray-700">Tipo de Cliente</label>
              <RadioGroup
                value={dadosEdicao.tipo}
                onValueChange={(v) => setDadosEdicao((p) => ({ ...p, tipo: v }))}
                className="flex gap-4"
              >
                <div className="flex items-center gap-2">
                  <RadioGroupItem value="pf" id="edit-tipo-pf" />
                  <Label htmlFor="edit-tipo-pf">Pessoa Física</Label>
                </div>
                <div className="flex items-center gap-2">
                  <RadioGroupItem value="pj" id="edit-tipo-pj" />
                  <Label htmlFor="edit-tipo-pj">Pessoa Jurídica</Label>
                </div>
              </RadioGroup>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="text-sm font-medium text-gray-700">{dadosEdicao.tipo === "pf" ? "Nome completo" : "Razão social"}</label>
                <AdminInput variant="form" value={dadosEdicao.nome} onChange={(e) => setDadosEdicao((p) => ({ ...p, nome: e.target.value }))} />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-gray-700">{dadosEdicao.tipo === "pf" ? "CPF" : "CNPJ"}</label>
                <AdminInput variant="form" value={dadosEdicao.documento} onChange={(e) => setDadosEdicao((p) => ({ ...p, documento: e.target.value }))} />
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium text-gray-700">E-mail principal</label>
              <AdminInput variant="form" value={dadosEdicao.email} onChange={(e) => setDadosEdicao((p) => ({ ...p, email: e.target.value }))} icon={<Mail size={15} />} />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="text-sm font-medium text-gray-700">Telefone</label>
                <AdminInput variant="form" value={dadosEdicao.telefone} onChange={(e) => setDadosEdicao((p) => ({ ...p, telefone: e.target.value }))} />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-gray-700">Cidade / Estado</label>
                <AdminInput variant="form" value={dadosEdicao.cidade} onChange={(e) => setDadosEdicao((p) => ({ ...p, cidade: e.target.value }))} icon={<MapPin size={15} />} />
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium text-gray-700">Status</label>
              <select
                value={dadosEdicao.status}
                onChange={(e) => setDadosEdicao((p) => ({ ...p, status: e.target.value as ClienteStatus }))}
                className="w-full h-10 rounded-xl border border-gray-200 bg-gray-50 px-3 text-sm text-gray-700 focus:outline-none focus:ring-2 focus:ring-[#0B7A8F]/20 focus:border-[#0B7A8F]"
              >
                <option value="ativo">Ativo</option>
                <option value="pendente">Pendente</option>
                <option value="inativo">Inativo</option>
              </select>
            </div>
          </AdminModalBody>
          <AdminModalFooter>
            <AdminButton variant="outline" onClick={() => setClienteEditando(null)}>Cancelar</AdminButton>
            <AdminButton variant="primary" onClick={handleSalvarEdicao}>Salvar alterações</AdminButton>
          </AdminModalFooter>
        </AdminModal>
      )}

      {/* ── Modal Condição Especial ──────────────────────────────────────────── */}
      {showModalCondicao && clienteSelecionado && (
        <AdminModal onClose={handleCancelarCondicao} size="md">
          <AdminModalHeader
            title="Condição Especial"
            subtitle={`Aplicar condição para ${clienteSelecionado.nome}`}
            onClose={handleCancelarCondicao}
          />
          <AdminModalBody>
            <div className="flex items-center gap-4 p-4 bg-gray-50 rounded-xl">
              <div className="h-12 w-12 rounded-full bg-[#0B7A8F]/10 flex items-center justify-center">
                {clienteSelecionado.tipo === "pj" ? <Building2 size={20} className="text-[#0B7A8F]" /> : <User size={20} className="text-[#0B7A8F]" />}
              </div>
              <div className="flex-1">
                <p className="font-semibold text-gray-900">{clienteSelecionado.nome}</p>
                <div className="flex items-center gap-2 mt-1 flex-wrap">
                  <span className="text-xs font-medium px-2 py-0.5 rounded bg-gray-200 text-gray-600 uppercase">
                    {clienteSelecionado.tipo === "pf" ? "Pessoa Física" : "Pessoa Jurídica"}
                  </span>
                  <span className={`text-xs font-medium px-2 py-0.5 rounded ${planoConfig[clienteSelecionado.plano].className}`}>
                    Plano {planoConfig[clienteSelecionado.plano].label}
                  </span>
                  <span className="text-xs text-gray-500">{clienteSelecionado.documento}</span>
                </div>
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-sm font-medium text-gray-700">Tipo de Condição</label>
              <RadioGroup
                value={novaCondicao.tipoCondicao}
                onValueChange={(v) => setNovaCondicao((p) => ({ ...p, tipoCondicao: v as Condicao["tipoCondicao"] }))}
                className="flex flex-col gap-3"
              >
                {clienteSelecionado.tipo === "pf" && (
                  <div className="flex items-start gap-3 p-3 border border-gray-200 rounded-xl hover:border-[#0B7A8F] transition-colors cursor-pointer">
                    <RadioGroupItem value="funcoes_pj" id="cond-funcoes-pj" className="mt-0.5" />
                    <div>
                      <Label htmlFor="cond-funcoes-pj" className="font-medium cursor-pointer">Funções de PJ</Label>
                      <p className="text-xs text-gray-500 mt-0.5">Habilita funcionalidades de pessoa jurídica para este cliente PF</p>
                    </div>
                  </div>
                )}
                <div className="flex items-start gap-3 p-3 border border-gray-200 rounded-xl hover:border-[#0B7A8F] transition-colors cursor-pointer">
                  <RadioGroupItem value="desconto" id="cond-desconto" className="mt-0.5" />
                  <div>
                    <Label htmlFor="cond-desconto" className="font-medium cursor-pointer">Desconto Especial</Label>
                    <p className="text-xs text-gray-500 mt-0.5">Aplica um percentual de desconto em todas as vistorias</p>
                  </div>
                </div>
                <div className="flex items-start gap-3 p-3 border border-gray-200 rounded-xl hover:border-[#0B7A8F] transition-colors cursor-pointer">
                  <RadioGroupItem value="prazo_especial" id="cond-prazo" className="mt-0.5" />
                  <div>
                    <Label htmlFor="cond-prazo" className="font-medium cursor-pointer">Prazo Especial</Label>
                    <p className="text-xs text-gray-500 mt-0.5">Estende o prazo de pagamento para este cliente</p>
                  </div>
                </div>
              </RadioGroup>
            </div>

            {(novaCondicao.tipoCondicao === "desconto" || novaCondicao.tipoCondicao === "funcoes_pj") && (
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-sm font-medium text-gray-700 flex items-center gap-2"><Percent size={14} />Desconto (%)</label>
                  <AdminInput variant="form" type="number" min={0} max={100} value={novaCondicao.desconto} onChange={(e) => setNovaCondicao((p) => ({ ...p, desconto: Number(e.target.value) }))} />
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-medium text-gray-700">Prazo de pagamento (dias)</label>
                  <AdminInput variant="form" type="number" min={1} value={novaCondicao.prazo} onChange={(e) => setNovaCondicao((p) => ({ ...p, prazo: Number(e.target.value) }))} />
                </div>
              </div>
            )}

            {novaCondicao.tipoCondicao === "prazo_especial" && (
              <div className="space-y-2">
                <label className="text-sm font-medium text-gray-700">Prazo de pagamento (dias)</label>
                <AdminInput variant="form" type="number" min={1} value={novaCondicao.prazo} onChange={(e) => setNovaCondicao((p) => ({ ...p, prazo: Number(e.target.value) }))} />
              </div>
            )}

            <div className="space-y-2">
              <label className="text-sm font-medium text-gray-700 flex items-center gap-2"><Calendar size={14} />Vigência da Condição</label>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <span className="text-xs text-gray-500">Data início</span>
                  <AdminInput variant="form" type="date" value={novaCondicao.vigenciaInicio} onChange={(e) => setNovaCondicao((p) => ({ ...p, vigenciaInicio: e.target.value }))} />
                </div>
                <div className="space-y-1">
                  <span className="text-xs text-gray-500">Data fim</span>
                  <AdminInput variant="form" type="date" value={novaCondicao.vigenciaFim} onChange={(e) => setNovaCondicao((p) => ({ ...p, vigenciaFim: e.target.value }))} />
                </div>
              </div>
            </div>

            <div className="p-4 bg-[#0B7A8F]/5 border border-[#0B7A8F]/20 rounded-xl">
              <p className="text-sm font-medium text-[#0B7A8F]">Resumo da Condição</p>
              <ul className="mt-2 space-y-1 text-sm text-gray-600">
                <li>• Tipo: <span className="font-medium">{tipoCondicaoConfig[novaCondicao.tipoCondicao].label}</span></li>
                {novaCondicao.desconto > 0 && <li>• Desconto: <span className="font-medium">{novaCondicao.desconto}%</span></li>}
                <li>• Prazo: <span className="font-medium">{novaCondicao.prazo} dias</span></li>
                {novaCondicao.vigenciaFim && <li>• Válido até: <span className="font-medium">{novaCondicao.vigenciaFim}</span></li>}
              </ul>
            </div>
          </AdminModalBody>
          <AdminModalFooter>
            <AdminButton variant="outline" onClick={handleCancelarCondicao}>Cancelar</AdminButton>
            <AdminButton variant="primary" onClick={handleSalvarCondicao} disabled={!isCondicaoFormValid}>Salvar Condição</AdminButton>
          </AdminModalFooter>
        </AdminModal>
      )}

      {/* ── Modal Tabela de Preços ───────────────────────────────────────────── */}
      {showModalTabelaPrecos && condicaoTabela && (
        <AdminModal onClose={() => setShowModalTabelaPrecos(false)} size="lg">
          <AdminModalHeader
            title="Tabela de Preços"
            subtitle={`Valores de ${condicaoTabela.clienteNome}`}
            onClose={() => setShowModalTabelaPrecos(false)}
          />
          <AdminModalBody>
            <div className="space-y-2">
              <label className="text-sm font-medium text-gray-700">Tipo de Cliente</label>
              <RadioGroup
                value={tabelaPrecos.tipoConta}
                onValueChange={(v) => setTabelaPrecos((p) => ({ ...p, tipoConta: v as "pf" | "pj" }))}
                className="flex gap-4"
              >
                <div className="flex items-center gap-2">
                  <RadioGroupItem value="pf" id="tabela-tipo-pf" />
                  <Label htmlFor="tabela-tipo-pf">Pessoa Física</Label>
                </div>
                <div className="flex items-center gap-2">
                  <RadioGroupItem value="pj" id="tabela-tipo-pj" />
                  <Label htmlFor="tabela-tipo-pj">Pessoa Jurídica</Label>
                </div>
              </RadioGroup>
            </div>
            <TabelaPrecosForm tabela={tabelaPrecos} onChange={setTabelaPrecos} />
          </AdminModalBody>
          <AdminModalFooter>
            <AdminButton variant="outline" onClick={() => setShowModalTabelaPrecos(false)}>Cancelar</AdminButton>
            <AdminButton variant="primary" onClick={() => setShowModalTabelaPrecos(false)}>Salvar</AdminButton>
          </AdminModalFooter>
        </AdminModal>
      )}
    </AdminDashboardLayout>
  )
}

