  // ─── Config Padrão ───────────────────────────────────────────────────────────
  const [configPF, setConfigPF] = useState<TabelaPrecos>({
    tipoConta: "pf",
    faixas: PRECOS_PADRAO_PF.faixas.map((f) => ({ ...f })),
